async function main() {
  console.log('🌱 Mulai seeding...')

  // ----- PTN -----
  console.log(`📚 Menyimpan ${PTN_DATA.length} PTN...`)
  for (const ptn of PTN_DATA) {
    await prisma.pTN.upsert({
      where: { id: ptn.id },
      update: {
        nama: ptn.nama,
        singkatan: ptn.singkatan,
        provinsi: ptn.provinsi,
        tipe: ptn.tipe,
      },
      create: {
        id: ptn.id,
        nama: ptn.nama,
        singkatan: ptn.singkatan,
        kota: ptn.kota,
        provinsi: ptn.provinsi,
        akreditasi: ptn.akreditasi,
        tipe: ptn.tipe,
      },
    })
  }
  console.log(`   ✅ ${PTN_DATA.length} PTN disimpan`)

  // ----- Jurusan (batched) -----
  console.log(`🎓 Menyimpan ${JURUSAN_DATA.length} Jurusan...`)
  const BATCH_SIZE = 500
  let processed = 0
  const totalBatches = Math.ceil(JURUSAN_DATA.length / BATCH_SIZE)

  for (let i = 0; i < JURUSAN_DATA.length; i += BATCH_SIZE) {
    const batch = JURUSAN_DATA.slice(i, i + BATCH_SIZE)
    const batchNum = Math.floor(i / BATCH_SIZE) + 1

    await prisma.$transaction(
      batch.map((j) =>
        prisma.jurusan.upsert({
          where: { id: j.id },
          update: {
            nama: j.nama,
            kode: j.kode,
            jenjang: j.jenjang,
            kelompok: j.kelompok,
            dayaTampung: j.dayaTampung,
            passingGrade: j.passingGrade,
          },
          create: {
            id: j.id,
            ptnId: j.ptnId,
            nama: j.nama,
            kode: j.kode,
            fakultas: j.fakultas,
            jenjang: j.jenjang,
            kelompok: j.kelompok,
            dayaTampung: j.dayaTampung,
            passingGrade: j.passingGrade,
          },
        })
      )
    )

    processed += batch.length
    console.log(`   Batch ${batchNum}/${totalBatches} — ${processed} jurusan diproses`)
  }

  console.log(`   ✅ ${JURUSAN_DATA.length} Jurusan disimpan`)
  console.log('\n🎉 Seeding selesai!')
}

main()
  .catch((e) => {
    console.error('❌ Error saat seeding:', e)
    process.exit(1)
  })
  .finally(async () => {
    await prisma.$disconnect()
  })